def solve(n: Long): String = {
  def toBase36(n: Long): String = {
    if (n == 0) "0"
    else {
      val digits = scala.collection.mutable.ListBuffer[Char]()
      var num = n
      while (num > 0) {
        val remainder = num % 36
        num = num / 36
        val c = if (remainder < 10) (remainder + '0').toChar else ('A' + (remainder - 10)).toChar
        digits.appendLeft(c)
      }
      digits.mkString
    }
  }
  val n2 = n * n
  val hexStr = n2.toHexString.toUpperCase
  val n3 = n * n * n
  val base36Str = toBase36(n3)
  hexStr + base36Str
}
